INSERT INTO psychiatric_assessment (client_id, clinician_id, assessment_date, assessment_time, assessment_type, presenting_problem, history_of_present_illness, psychiatric_history, substance_use_history, mental_status_exam, mood_description, affect_description, thought_process, thought_content, suicidal_ideation, homicidal_ideation, insight_level, judgment_level, risk_level, dsm5_diagnosis_primary, dsm5_code_primary, dsm5_diagnosis_secondary, dsm5_code_secondary, severity_rating, assessment_summary) VALUES
(1, 1, '2025-02-15', '10:00', 'INTAKE', 'Severe depression, suicidal thoughts', 'Patient reports 3-month history of worsening depression with passive suicidal ideation. Unable to work, social withdrawal, poor self-care.', 'First psychiatric hospitalization. Outpatient therapy x 6 months with limited benefit. Family history positive for depression and suicide.', 'Denies current use. Social alcohol use in past.', 'Alert, cooperative. Psychomotor retardation noted.', 'Depressed, hopeless', 'Constricted, tearful', 'Linear, goal-directed', 'Preoccupation with feelings of worthlessness, passive death wishes', 'PASSIVE', 'NONE', 'Fair', 'Fair', 'MODERATE', 'Major Depressive Disorder, Severe', 'F33.2', NULL, NULL, 'Severe', 'Severe major depression with passive SI, requiring inpatient stabilization and medication management.'),
(2, 4, '2025-02-18', '14:30', 'INTAKE', 'Alcohol dependence, depression', 'Patient brought in by family after 5-day drinking binge. Reports drinking daily for past 10 years, increased last 6 months after job loss. Mild withdrawal symptoms present.', 'History of depression treated with antidepressants. Previous detox admissions x2.', 'Alcohol: 12-15 beers daily. Last drink 24 hours ago. Denies other substances.', 'Alert, slightly tremulous. Mild diaphoresis.', 'Anxious, dysphoric', 'Anxious, restricted', 'Linear', 'Guilt about drinking, worry about family', 'NONE', 'NONE', 'Fair', 'Impaired', 'LOW', 'Alcohol Use Disorder, Severe', 'F10.20', 'Major Depressive Disorder, Recurrent', 'F33.1', 'Severe', 'Severe alcohol use disorder with depression. Requires medically supervised detox and dual diagnosis treatment.'),
(3, 2, '2025-02-20', '11:00', 'INTAKE', 'Self-harm, depression, school refusal', '17-year-old male with 6-month history of depression, cutting behaviors, academic decline. Parents report social isolation, gaming for 12+ hours daily. Recent breakup with girlfriend.', 'No previous psychiatric treatment. Bullying history in middle school.', 'Admits to marijuana use on weekends with friends. Denies other substances.', 'Alert, guarded initially, opens up during interview.', 'Sad, irritable', 'Labile', 'Linear', 'Self-deprecating thoughts, feeling like a burden to family', 'ACTIVE_NO_PLAN', 'NONE', 'Limited', 'Limited', 'MODERATE', 'Major Depressive Disorder, Single Episode, Moderate', 'F32.1', 'Cannabis Use Disorder, Mild', 'F12.10', 'Moderate', 'Adolescent depression with NSSI and cannabis use. Family dynamics assessment needed. Inpatient stabilization appropriate.'),
(4, 3, '2025-02-22', '09:30', 'INTAKE', 'Paranoia, confusion, agitation', '78-year-old female brought to ED by son due to increasing paranoia, accusing family of stealing, refusing medications. Progressive decline over 3 months.', 'History of late-onset depression, treated with sertraline. Increasing memory problems noted by family over past year.', 'Denies. Takes multiple medications for hypertension, diabetes.', 'Alert but disoriented to place and time. Poor attention and concentration.', 'Anxious, suspicious', 'Blunted', 'Tangential at times', 'Paranoid ideation regarding family members stealing possessions', 'NONE', 'NONE', 'Poor', 'Poor', 'MODERATE', 'Major Neurocognitive Disorder, Probable Alzheimer''s, with Behavioral Disturbance', 'F02.81', 'Unspecified Psychotic Disorder', 'F29', 'Moderate', 'Dementia with psychotic features requiring stabilization and medication adjustment. Caregiver education needed.'),
(5, 1, '2025-02-25', '15:00', 'INTAKE', 'Bipolar disorder, manic episode', 'Patient presents with decreased need for sleep x 1 week, rapid speech, grandiose ideas about starting multiple businesses. Stopped taking lithium 3 weeks ago stating he felt great.', 'Bipolar I disorder diagnosed 10 years ago. Multiple hospitalizations for mania. Medication non-compliance pattern.', 'Increased alcohol use during manic episodes. Currently denies.', 'Hyperactive, pressured speech, flight of ideas noted.', 'Elevated, euphoric', 'Expansive', 'Flight of ideas', 'Grandiose plans, increased goal-directed activity', 'NONE', 'NONE', 'Poor', 'Impaired', 'MODERATE', 'Bipolar I Disorder, Current Episode Manic, Severe', 'F31.13', NULL, NULL, 'Severe', 'Manic episode in context of medication non-adherence. Requires mood stabilization and medication compliance work.'),
(6, 1, '2025-02-28', '13:00', 'INTAKE', 'Suicidal crisis, borderline traits', '24-year-old with chronic SI and multiple suicide attempts (cutting, overdose). Current crisis triggered by relationship breakup. Presents with fresh cutting injuries.', 'Multiple psychiatric hospitalizations starting age 16. Diagnoses have included depression, PTSD, borderline personality disorder. History of childhood sexual abuse.', 'Daily marijuana use. Occasional binge drinking. History of other substance experimentation.', 'Alert, intense presentation, labile affect throughout interview.', 'Dysphoric, angry', 'Labile', 'Linear', 'Intense abandonment fears, identity confusion, chronic emptiness', 'ACTIVE_WITH_PLAN', 'NONE', 'Limited', 'Limited', 'HIGH', 'Borderline Personality Disorder', 'F60.3', 'Major Depressive Disorder, Recurrent', 'F33.1', 'Severe', 'High-risk patient with BPD and acute suicidal crisis. Safety concerns require inpatient stabilization. DBT indicated.'),
(7, 4, '2026-01-05', '10:30', 'INTAKE', 'Cocaine dependence, paranoia', 'Patient using cocaine daily x 6 months. Spending entire paycheck on drugs. Wife threatening to leave. Experiencing paranoia that people are following him.', 'No previous psychiatric treatment. Brother has substance use disorder.', 'Cocaine: 2-3 grams daily. Last use 36 hours ago. Also smoking marijuana daily. Alcohol on weekends.', 'Alert, hypervigilant, scanning environment frequently.', 'Anxious', 'Constricted', 'Circumstantial', 'Paranoid thoughts about being followed, monitored', 'NONE', 'NONE', 'Fair', 'Impaired', 'MODERATE', 'Stimulant Use Disorder, Severe (Cocaine)', 'F14.20', 'Stimulant-Induced Psychotic Disorder', 'F14.959', 'Severe', 'Severe cocaine use disorder with substance-induced psychosis. Requires detox and intensive substance abuse treatment.'),
(8, 2, '2026-01-10', '14:00', 'INTAKE', 'Anorexia nervosa, depression', '22-year-old female with 18-month history of restrictive eating, excessive exercise, 35-pound weight loss. Current BMI 16.5. Medical concerns include bradycardia and electrolyte abnormalities.', 'History of anxiety and perfectionism. Some depression symptoms. No previous eating disorder treatment.', 'Denies. Caffeine use for appetite suppression.', 'Alert, thin appearance, cooperative but minimizes concerns.', 'Anxious', 'Restricted', 'Linear', 'Distorted body image, intense fear of weight gain, preoccupation with food and calories', 'NONE', 'NONE', 'Poor regarding illness severity', 'Fair', 'HIGH', 'Anorexia Nervosa, Restricting Type, Severe', 'F50.01', 'Generalized Anxiety Disorder', 'F41.1', 'Severe', 'Severe anorexia nervosa with medical complications requiring stabilization. Multidisciplinary treatment needed.');
INSERT INTO treatment_plan (client_id, primary_clinician_id, plan_start_date, plan_review_date, treatment_goals, objectives_interventions, therapeutic_modality, frequency_of_sessions, estimated_duration, discharge_criteria, plan_status, client_agreement_signed) VALUES
(1, 1, '2025-02-16', '2025-03-16', 'Goal 1: Patient will report reduction in suicidal ideation. Goal 2: Patient will demonstrate improved mood and functioning. Goal 3: Patient will identify coping strategies for managing depression.', 'Obj 1a: Participate in individual therapy 3x/week. Obj 1b: Engage in medication management. Obj 2a: Attend group therapy daily. Obj 3a: Develop safety plan with triggers and coping skills.', 'CBT, Supportive Therapy', '3 individual sessions per week, daily group therapy', '4-6 weeks', 'No active SI for 72 hours, stable on medications, safe discharge plan in place, outpatient follow-up arranged.', 'ACTIVE', TRUE),
(2, 4, '2025-02-19', '2025-03-19', 'Goal 1: Complete safe medical detoxification. Goal 2: Engage in dual diagnosis treatment. Goal 3: Develop relapse prevention plan.', 'Obj 1a: Medical monitoring during detox. Obj 1b: Medication management for withdrawal. Obj 2a: Individual therapy 2x/week. Obj 2b: Dual diagnosis group daily. Obj 3a: Identify triggers and high-risk situations.', 'Motivational Interviewing, 12-Step Facilitation', 'Daily group therapy, individual therapy 2x/week', '3-4 weeks', 'Medically stable, engaged in recovery, attending AA/NA, outpatient or residential treatment arranged.', 'ACTIVE', TRUE),
(3, 2, '2025-02-21', '2025-03-21', 'Goal 1: Patient will refrain from self-harm behaviors. Goal 2: Patient will learn healthy coping skills. Goal 3: Patient will improve communication with family.', 'Obj 1a: Use safety plan when having urges to self-harm. Obj 1b: Participate in DBT skills groups. Obj 2a: Practice distress tolerance skills. Obj 3a: Participate in family therapy sessions.', 'DBT, Family Therapy', 'Individual therapy 2x/week, DBT skills group 3x/week, family therapy 1x/week', '4-6 weeks', 'No self-harm x 2 weeks, using coping skills effectively, improved family communication, school re-entry plan.', 'ACTIVE', TRUE),
(4, 3, '2025-02-23', '2025-03-23', 'Goal 1: Reduce agitation and paranoia. Goal 2: Improve cognitive functioning to baseline. Goal 3: Establish safe discharge plan with family support.', 'Obj 1a: Medication adjustment for behavioral symptoms. Obj 1b: Structured daily activities. Obj 2a: Cognitive assessment. Obj 3a: Family education on dementia care. Obj 3b: Evaluate need for assisted living.', 'Supportive Therapy, Reality Orientation', 'Daily group activities, family meetings 2x/week', '2-3 weeks', 'Behavioral symptoms controlled, family educated and able to provide care or placement arranged.', 'ACTIVE', TRUE),
(5, 1, '2025-02-26', '2025-03-26', 'Goal 1: Stabilize mood. Goal 2: Resume medication adherence. Goal 3: Recognize warning signs of mood episodes.', 'Obj 1a: Mood stabilizer medication management. Obj 1b: Daily mood monitoring. Obj 2a: Psychoeducation on bipolar disorder. Obj 2b: Address barriers to medication adherence. Obj 3a: Identify personal relapse warning signs.', 'Psychoeducation, Supportive Therapy', 'Daily psychiatry check-ins, group therapy 5x/week', '2-3 weeks', 'Mood stable, therapeutic medication levels, insight into illness, medication adherence plan in place.', 'ACTIVE', TRUE);
INSERT INTO therapy_session (client_id, clinician_id, session_date, session_start_time, session_end_time, session_duration_minutes, session_modality, session_type, attendance_status, client_presentation, topics_addressed, interventions_used, client_response, risk_assessment_summary, progress_toward_goals, session_note_signed, signature_timestamp) VALUES
(1, 1, '2025-02-17', '10:00', '10:50', 50, 'INDIVIDUAL', 'IN_PERSON', 'ATTENDED', 'Patient tearful but engaged, making good eye contact.', 'Discussed current depression symptoms, SI timeline, identified triggers including isolation and negative self-talk.', 'CBT techniques: cognitive restructuring of negative thoughts, developed initial safety plan.', 'Patient receptive to interventions, able to identify some automatic negative thoughts.', 'Passive SI present but no plan or intent. Safety plan established. Low acute risk.', 'Beginning to engage in treatment. Identifying cognitive patterns contributing to depression.', TRUE, '2025-02-17 11:00:00'),
(2, 4, '2025-02-20', '14:00', '14:45', 45, 'INDIVIDUAL', 'IN_PERSON', 'ATTENDED', 'Patient calmer than admission, withdrawal symptoms resolving. More open about substance use.', 'Reviewed substance use history in detail, explored connection between alcohol use and depression, discussed impact on family.', 'Motivational interviewing: explored ambivalence about sobriety, change talk elicited.', 'Patient expressing some motivation for change, acknowledging negative consequences of use.', 'No SI/HI. Medically stable. Committed to staying in treatment.', 'Beginning to develop insight into dual diagnosis. Early engagement in recovery.', TRUE, '2025-02-20 15:00:00'),
(3, 2, '2025-02-22', '15:00', '15:50', 50, 'INDIVIDUAL', 'IN_PERSON', 'ATTENDED', 'Adolescent initially guarded but warmed up during session. Less defensive than admission.', 'Explored precipitants to current crisis, discussed feelings about girlfriend breakup, examined pattern of self-harm as coping.', 'DBT: introduced concept of emotion regulation, taught TIPP skill for distress tolerance.', 'Patient engaged well, practiced TIPP skill in session, reported it was helpful.', 'SI decreased to moderate level. Denies current self-harm urges. Using coping card.', 'Good progress. Learning alternative coping skills. Reduced SI.', TRUE, '2025-02-22 16:00:00'),
(5, 1, '2025-02-27', '09:00', '09:30', 30, 'INDIVIDUAL', 'IN_PERSON', 'ATTENDED', 'Patient still somewhat elevated but less grandiose. Sleep improving with medication.', 'Psychoeducation about bipolar disorder, reviewed prior episodes and pattern of stopping medication, explored consequences.', 'Motivational enhancement: examined pros/cons of medication adherence.', 'Patient beginning to show more insight, acknowledges need for consistent treatment.', 'No current safety concerns. Mood stabilizing.', 'Developing insight into illness. More willing to discuss medication maintenance.', TRUE, '2025-02-27 09:45:00'),
(6, 5, '2025-03-01', '11:00', '11:50', 50, 'INDIVIDUAL', 'IN_PERSON', 'ATTENDED', 'Patient emotionally intense, alternating between tears and anger. Splitting noted.', 'Addressed recent relationship loss, explored pattern of intense unstable relationships, worked on distress tolerance.', 'DBT: STOP skill taught and practiced, validation of emotions while addressing maladaptive behaviors.', 'Patient able to use STOP skill by end of session to decrease emotional intensity.', 'SI fluctuating but manageable with coping skills. No recent cutting. Safety plan reviewed.', 'Small gains in emotional regulation. Needs continued intensive DBT work.', TRUE, '2025-03-01 12:00:00');
INSERT INTO psych_medication_formulary (medication_name, generic_equivalent, drug_category, controlled_class, black_box_warning_text, typical_starting_dose, therapeutic_range, monitoring_requirements) VALUES
('Sertraline', 'Sertraline HCl', 'SSRI Antidepressant', NULL, 'Increased risk of suicidal thinking and behavior in children, adolescents, and young adults taking antidepressants.', '50mg daily', '50-200mg daily', 'Monitor for activation, suicidality, serotonin syndrome'),
('Lithium', 'Lithium Carbonate', 'Mood Stabilizer', NULL, 'Lithium toxicity is closely related to serum lithium levels.', '300mg twice daily', 'Serum level 0.6-1.2 mEq/L', 'Serum lithium levels, renal function, thyroid function'),
('Quetiapine', 'Quetiapine Fumarate', 'Atypical Antipsychotic', NULL, 'Increased mortality in elderly patients with dementia-related psychosis.', '25-50mg at bedtime', '150-800mg daily', 'Metabolic panel, lipids, weight, movement disorders'),
('Lorazepam', 'Lorazepam', 'Benzodiazepine', 'C-IV', 'Risk of abuse, misuse, and addiction. Physical dependence and withdrawal.', '0.5-1mg', '1-6mg daily divided', 'Monitor for sedation, respiratory depression, dependence'),
('Naltrexone', 'Naltrexone HCl', 'Opioid Antagonist', NULL, 'Risk of hepatotoxicity at higher doses.', '50mg daily', '50-100mg daily', 'Liver function tests, ensure opioid-free before starting'),
('Fluoxetine', 'Fluoxetine HCl', 'SSRI Antidepressant', NULL, 'Increased risk of suicidal thinking and behavior in children, adolescents, and young adults.', '20mg daily', '20-80mg daily', 'Monitor for activation, suicidality, serotonin syndrome'),
('Aripiprazole', 'Aripiprazole', 'Atypical Antipsychotic', NULL, 'Increased mortality in elderly patients with dementia-related psychosis.', '5-10mg daily', '10-30mg daily', 'Metabolic monitoring, movement disorders, akathisia'),
('Buprenorphine/Naloxone', 'Buprenorphine/Naloxone', 'Opioid Partial Agonist', 'C-III', 'Risk of addiction, abuse, and misuse. Risk of respiratory depression.', '4/1mg daily', '8/2mg to 24/6mg daily', 'Monitor for diversion, precipitated withdrawal'),
('Valproic Acid', 'Divalproex Sodium', 'Mood Stabilizer', NULL, 'Hepatotoxicity, teratogenicity, pancreatitis.', '250mg twice daily', 'Serum level 50-125 mcg/mL', 'Serum levels, liver function, CBC, ammonia'),
('Risperidone', 'Risperidone', 'Atypical Antipsychotic', NULL, 'Increased mortality in elderly patients with dementia-related psychosis.', '0.5-1mg', '2-6mg daily', 'Metabolic monitoring, prolactin, movement disorders');
