INSERT INTO group_therapy (group_name, facilitator_id, co_facilitator_id, session_date, session_time, duration_minutes, group_type, topic_focus, session_notes, attendance_count) VALUES
('CBT Skills Group', 5, NULL, '2025-02-17', '14:00', 60, 'SKILLS', 'Identifying Automatic Negative Thoughts', 'Good group participation. Patients shared examples of ANTs and practiced challenging them with evidence.', 8),
('Dual Diagnosis Group', 4, 6, '2025-02-19', '10:00', 90, 'PSYCHOEDUCATION', 'The Connection Between Substance Use and Mental Health', 'Interactive session. Patients identified their own patterns of self-medication. Good insight development.', 6),
('DBT Skills Group', 5, NULL, '2025-02-22', '15:00', 90, 'SKILLS', 'Distress Tolerance: TIPP Skills', 'Taught and practiced TIPP skills. Several patients reported using skills between sessions successfully.', 7),
('Wellness and Recovery', 6, NULL, '2025-02-23', '11:00', 60, 'SUPPORT', 'Building Your Support Network', 'Patients discussed importance of support systems and identified people they can reach out to.', 9),
('Relapse Prevention', 4, NULL, '2025-02-25', '13:00', 60, 'PSYCHOEDUCATION', 'Identifying Triggers and High-Risk Situations', 'Patients created personalized trigger lists and discussed coping strategies for each trigger.', 5),
('Mindfulness Practice', 5, NULL, '2025-02-26', '09:00', 45, 'SKILLS', 'Guided Mindfulness Meditation', 'Guided 20-minute meditation followed by processing. Most patients able to stay present.', 10);
INSERT INTO group_attendance (group_session_id, client_id, attendance_status, participation_level, clinical_notes) VALUES
(1, 1, 'PRESENT', 'MODERATE', 'Patient participated, shared one example of negative thought.'),
(1, 3, 'PRESENT', 'ACTIVE', 'Highly engaged, excellent examples shared, helped other group members.'),
(2, 2, 'PRESENT', 'ACTIVE', 'Openly discussed pattern of drinking when depressed. Good insight.'),
(2, 7, 'PRESENT', 'MODERATE', 'Participated when prompted, some defensiveness noted.'),
(3, 3, 'PRESENT', 'ACTIVE', 'Demonstrated TIPP skill correctly. Reported using it successfully.'),
(3, 6, 'PRESENT', 'ACTIVE', 'Very engaged. Practiced skills and asked good questions.'),
(4, 1, 'PRESENT', 'MINIMAL', 'Present but quiet. Identified mother as support person.'),
(4, 5, 'PRESENT', 'MODERATE', 'Discussed need to reconnect with old friends from before illness.'),
(5, 2, 'PRESENT', 'ACTIVE', 'Created detailed trigger list. Identified specific high-risk situations.'),
(6, 1, 'PRESENT', 'MODERATE', 'Able to focus during meditation. Reports it was helpful.');
INSERT INTO crisis_incident (client_id, incident_datetime, reporting_staff_id, incident_type, severity_level, incident_location, detailed_description, antecedents, interventions_applied, restraint_used, seclusion_used, prn_medication_given, outcome_resolution, followup_plan) VALUES
(6, '2025-02-28 22:30:00', 8, 'SELF_HARM', 'MODERATE', 'Patient Bathroom', 'Patient found with superficial scratches on forearm. Disclosed she used fingernails after triggering phone call with ex-partner.', 'Received upsetting phone call from ex-partner approximately 30 minutes prior. Did not use call for help or coping skills.', 'One-to-one observation initiated. Processed incident with staff. Safety plan reviewed. Called for PRN medication evaluation.', FALSE, FALSE, TRUE, 'Patient calmed with verbal support and PRN medication. Agreed to ask for help if urges return. Wounds cleaned and dressed.', 'Continue one-to-one observation for 4 hours. Psychiatry notified. Process incident in individual therapy.'),
(3, '2025-02-21 15:15:00', 7, 'AGGRESSION', 'MINOR', 'Day Room', 'Patient became verbally aggressive with peer after dispute over TV channel. Raised voice, made threatening statement but no physical contact.', 'Patient appeared irritable throughout the day. Conflict arose over TV remote with another patient.', 'Staff intervened verbally. Separated patients. Offered patient time in quiet area and PRN medication. Patient chose quiet time over medication.', FALSE, FALSE, FALSE, 'Patient calmed after 20 minutes in quiet area. Able to process incident and identify better ways to handle frustration. Apologized to peer.', 'Monitor for continued irritability. Review anger management skills in therapy.'),
(7, '2026-01-06 03:00:00', 8, 'AGITATION', 'MODERATE', 'Patient Room', 'Patient unable to sleep, pacing in room, expressing paranoid ideation about staff "poisoning" medications. Becoming increasingly agitated.', 'Patient in active cocaine withdrawal. Paranoid thoughts worsening despite medication. Sleep deprivation contributing.', 'Verbal de-escalation attempted. PRN medication offered and accepted. Psychiatrist contacted for medication review.', FALSE, FALSE, TRUE, 'Patient calmed after PRN medication. Able to sleep for 4 hours. Paranoid thoughts improved but not resolved. Medication adjustment made.', 'Continue close monitoring. Medication adjustment per psychiatry. Reality orientation as needed.');
